70в†’            now = datetime.utcnow()
71в†’            is_esp_online = m.last_seen and (now - m.last_seen).total_seconds() < 60
72в†’            if not is_esp_online:
73в†’                status = "OFFLINE"
74в†’            elif m.current_baud == 0:
75в†’                status = "ESP_ONLINE_NO_SIGNAL"
76в†’            elif remaining <= 0:
77в†’                status = "ASNOVA_EMPTY"
78в†’            else:
79в†’                status = "RUNNING"
