48в†’        <div className="login-field">
49в†’          <label>Foydalanuvchi</label>
50в†’          <input 
51в†’            type="text" 
52в†’            placeholder="Login kiriting"
53в†’            value={username} 
54в†’            onChange={(e) => setUsername(e.target.value)} 
55в†’            required 
56в†’            autoFocus
57в†’          />
58в†’        </div>
59в†’
60в†’        <div className="login-field">
61в†’          <label>Parol</label>
62в†’          <input 
